namespace sv_f6ea5319dfc146ad8a4e633bf667692f.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// Interactive components subscribe to OnChange to react when any component
/// mutates the theme.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set { if (_theme != value) { _theme = value; NotifyChanged(); } }
    }

    public string AccentColor
    {
        get => _accentColor;
        set { if (_accentColor != value) { _accentColor = value; NotifyChanged(); } }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@* Interactive island embedded in the static MainLayout.
   Because it runs with InteractiveServer, it joins the circuit
   and shares the same scoped ThemeService as every page component. *@

@using sv_f6ea5319dfc146ad8a4e633bf667692f.Services
@inject ThemeService ThemeSvc
@implements IDisposable

<span class="theme-indicator" style="color: @ThemeSvc.AccentColor;" title="Current theme">
    @switch (ThemeSvc.Theme)
    {
        case ThemeMode.Light:
            <span>☀️ Light</span>
            break;
        case ThemeMode.Dark:
            <span>🌙 Dark</span>
            break;
        case ThemeMode.System:
            <span>💻 System</span>
            break;
    }
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeSvc.OnChange -= HandleThemeChanged;
    }
}

@using sv_f6ea5319dfc146ad8a4e633bf667692f.Services
@inject ThemeService ThemeSvc
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        style="border-color: @ThemeSvc.AccentColor;">
    @ThemeSvc.Theme.ToString()
</button>

@code {
    private void CycleTheme()
    {
        ThemeSvc.Theme = ThemeSvc.Theme switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _ => ThemeMode.Light
        };
    }

    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += HandleChanged;
    }

    private void HandleChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeSvc.OnChange -= HandleChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer

@using sv_f6ea5319dfc146ad8a4e633bf667692f.Services
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h2>User Preferences</h2>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select w-auto" @bind="SelectedTheme">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <option value="@mode">@mode</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnColorChanged" />
    <span class="form-text">@ThemeSvc.AccentColor</span>
</div>

<div class="alert mt-4" style="border-left: 4px solid @ThemeSvc.AccentColor;">
    Preview — current theme is <strong>@ThemeSvc.Theme</strong>
    with accent <span style="color:@ThemeSvc.AccentColor;">@ThemeSvc.AccentColor</span>.
</div>

@code {
    private ThemeMode SelectedTheme
    {
        get => ThemeSvc.Theme;
        set => ThemeSvc.Theme = value;
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeSvc.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += HandleChanged;
    }

    private void HandleChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeSvc.OnChange -= HandleChanged;
    }
}

